{
  "short_persona": "A renowned neurologist specializing in music-related seizures and their treatment",
  "name": "Dr. Amara Njeri Okafor",
  "age": 46,
  "gender": "Female",
  "sexual_orientation": "Heterosexual",
  "race_ethnicity": "Nigerian, Igbo heritage (Sub-Saharan African)",
  "nationality": "Nigerian-born, naturalized U.S. citizen",
  "languages_spoken": [
    "English (fluent)",
    "Igbo (native)",
    "French (conversational)"
  ],
  "religion": "Culturally Christian with a modern secular outlook",
  "personality": {
    "traits": [
      "Intellectually curious",
      "Empathetic",
      "Analytical",
      "Patient",
      "Detail-oriented",
      "Humble despite expertise"
    ],
    "introversion_extroversion": "Balanced, leans toward introverted reflection in personal life but confident and engaging in professional settings",
    "emotional_tendencies": "Calm under pressure, deeply compassionate toward patients, with a quietly passionate advocacy for neurological research",
    "values": [
      "Scientific integrity",
      "Cross-cultural understanding",
      "Patient dignity",
      "Lifelong learning",
      "Art and music as healing tools"
    ]
  },
  "education": {
    "undergraduate_degree": {
      "degree": "B.Sc. in Neuroscience",
      "institution": "University of Lagos",
      "graduation_year": 2000
    },
    "medical_school": {
      "degree": "MD in Neurology",
      "institution": "University College Hospital, Ibadan",
      "graduation_year": 2006
    },
    "postgraduate_training": [
      {
        "degree": "Ph.D. in Neurophysiology",
        "institution": "Johns Hopkins University",
        "graduation_year": 2011
      },
      {
        "fellowship": "Epilepsy and Music Cognition Research Fellowship",
        "institution": "University of Cambridge",
        "completion_year": 2014
      }
    ]
  },
  "career": {
    "current_position": "Professor of Neurology & Director of the Music and Epilepsy Research Centre",
    "current_institution": "Columbia University Medical Center",
    "years_in_practice": 18,
    "notable_research": [
      "Pioneered diagnostic protocols for reflex epilepsy triggered by specific musical frequencies",
      "Developed novel non-invasive neurostimulation techniques integrating musical therapy",
      "Published over 80 peer-reviewed articles in neurology and neuroscience journals"
    ],
    "professional_affiliations": [
      "American Academy of Neurology",
      "International League Against Epilepsy",
      "Society for Music Perception and Cognition"
    ]
  },
  "location": {
    "city": "New York City",
    "country": "United States",
    "neighborhood": "Upper West Side, Manhattan"
  },
  "marital_status": "Married",
  "spouse": {
    "name": "Daniel Okafor",
    "occupation": "Architect specializing in sustainable urban design"
  },
  "children": [
    {
      "name": "Chinelo",
      "age": 14,
      "interests": [
        "Piano",
        "Robotics",
        "Documentary filmmaking"
      ]
    },
    {
      "name": "Obinna",
      "age": 10,
      "interests": [
        "Soccer",
        "Chess",
        "Astronomy"
      ]
    }
  ],
  "lifestyle": {
    "hobbies": [
      "Classical piano performance",
      "Jazz appreciation",
      "Cycling in Central Park",
      "Writing science outreach articles"
    ],
    "travel_preferences": [
      "Cultural cities with strong music heritage such as Vienna, Cape Town, and Havana"
    ],
    "diet": "Primarily pescatarian with occasional Nigerian traditional dishes",
    "fitness": "Morning yoga and weekend cycling"
  },
  "technology_habits": {
    "devices_used": [
      "High-end laptop",
      "Tablet with stylus for note-taking",
      "Noise-cancelling headphones for music analysis"
    ],
    "social_media": [
      "LinkedIn for professional networking",
      "Twitter for science communication"
    ],
    "AI_usage": "Uses AI for literature review, research summarization, and patient data analysis"
  },
  "speaking_style_to_chatbot": {
    "tone": "Warm yet precise \u2014 blends professional respect with curiosity; maintains an approachable demeanor even when discussing complex neuroscience topics",
    "formality": "Moderately formal \u2014 uses professional vocabulary but relaxes to casual phrasing when discussing personal or philosophical topics",
    "pacing": "Measured and deliberate \u2014 ensures clarity by avoiding rushed explanations; pauses to verify understanding when exploring complex ideas",
    "vocabulary": "Highly articulate \u2014 comfortable with advanced neurological and medical terminology, yet capable of breaking down concepts into layperson-friendly explanations; occasional use of culturally situated idioms or metaphors from both Nigerian and Western contexts",
    "interaction_tendencies": "Asks targeted, structured questions in research contexts; when discussing music or patient care, becomes more narrative-driven and storytelling-oriented; tends to clarify terms and confirm AI responses"
  },
  "example_chatbot_prompts": [
    "Can you summarize the most recent findings on auditory-triggered reflex epilepsy in less than 300 words?",
    "I'm preparing a lecture for non-medical students \u2014 could you suggest an illustrative analogy for explaining neural synchrony?",
    "I'd like to cross-reference multiple EEG studies that involve music therapy \u2014 can you compile the datasets into a comparative table?",
    "Could you recommend some contemporary jazz pieces composed in unusual time signatures for cognitive stimulation research?",
    "Please identify three potential ethical dilemmas in applying AI for neurological diagnostics in underserved populations."
  ]
}

